"""Interface for writing, compiling, and converting ``.tex`` files.

.. SEEALSO::

    :mod:`.mobject.svg.tex_mobject`

"""

from __future__ import annotations

import hashlib
import re
import subprocess
import unicodedata
from collections.abc import Generator, Iterable, Sequence
from pathlib import Path
from re import Match
from typing import Any

from manim.utils.tex import TexTemplate

from .. import config, logger

__all__ = ["tex_to_svg_file"]


def tex_hash(expression: Any) -> str:
    id_str = str(expression)
    hasher = hashlib.sha256()
    hasher.update(id_str.encode())
    # Truncating at 16 bytes for cleanliness
    return hasher.hexdigest()[:16]


def tex_to_svg_file(
    expression: str,
    environment: str | None = None,
    tex_template: TexTemplate | None = None,
) -> Path:
    r"""Takes a tex expression and returns the svg version of the compiled tex

    Parameters
    ----------
    expression
        String containing the TeX expression to be rendered, e.g. ``\\sqrt{2}`` or ``foo``
    environment
        The string containing the environment in which the expression should be typeset, e.g. ``align*``
    tex_template
        Template class used to typesetting. If not set, use default template set via `config["tex_template"]`

    Returns
    -------
    :class:`Path`
        Path to generated SVG file.
    """
    # iOS: Check early — no subprocess available for LaTeX compilation
    import os as _os
    _is_ios_tex = _os.path.exists("/var/mobile") or "ios" in __import__('sys').platform.lower()

    try:
        if tex_template is None:
            tex_template = config["tex_template"]
        tex_file = generate_tex_file(expression, environment, tex_template)
    except Exception as _gen_err:
        if _is_ios_tex:
            # Generate a temp path for the SVG
            import hashlib, tempfile
            _hash = hashlib.md5(expression.encode()).hexdigest()[:12]
            tex_file = __import__('pathlib').Path(tempfile.gettempdir()) / f"tex_{_hash}.tex"
            tex_file.write_text(expression, encoding="utf-8")
        else:
            raise

    # check if svg already exists
    svg_file = tex_file.with_suffix(".svg")
    if not _is_ios_tex and svg_file.exists():
        return svg_file
    # On iOS: always regenerate (cached files may be corrupt)
    if _is_ios_tex and svg_file.exists():
        try:
            svg_file.unlink()
        except Exception:
            pass

    if _is_ios_tex:
        # Use the raw expression directly — it's the math content
        # (e.g., "E = mc^2" or "a^2 + b^2 = c^2")
        # Don't try to parse the .tex file — it has preamble/encoding cruft
        import re as _re
        formula = expression.strip()
        # Strip \special{dvisvgm:raw ...} commands (manim injects these for pdftex+dvisvgm)
        formula = _re.sub(r"\\special\{dvisvgm:raw\s*<[^>]*>\}", '', formula)
        formula = _re.sub(r"\\special\{dvisvgm:raw\s*</[^>]*>\}", '', formula)
        formula = _re.sub(r"\\special\{[^}]*\}", '', formula)
        # Strip align* environment wrapper
        formula = _re.sub(r'\\begin\{align\*?\}', '', formula)
        formula = _re.sub(r'\\end\{align\*?\}', '', formula)
        formula = formula.strip()
        if not formula:
            formula = "?"

        # Offline Cairo rendering: convert LaTeX to plain ASCII text
        # iOS system fonts lack Unicode math chars (superscripts show as boxes)
        # Use plain readable notation instead
        display = formula

        # Fractions: \frac{a}{b} -> (a)/(b)
        display = _re.sub(r'\\frac\{([^}]*)\}\{([^}]*)\}', r'(\1)/(\2)', display)
        # Square root: \sqrt{x} -> sqrt(x)
        display = _re.sub(r'\\sqrt\{([^}]*)\}', r'sqrt(\1)', display)
        display = _re.sub(r'\\sqrt\s*(\w)', r'sqrt(\1)', display)
        # Keep superscripts/subscripts as plain text: x^{2} -> x^2, x_{i} -> x_i
        display = _re.sub(r'\^\{([^}]*)\}', r'^\1', display)
        display = _re.sub(r'_\{([^}]*)\}', r'_\1', display)
        # Integrals/sums
        display = display.replace('\\int', 'int').replace('\\sum', 'sum').replace('\\prod', 'prod')
        # Greek letters (only basic ones iOS fonts support)
        _greek_safe = {'alpha':'a','beta':'b','gamma':'y','delta':'d','epsilon':'e',
                       'theta':'O','lambda':'L','mu':'u','pi':'pi','sigma':'o','omega':'w',
                       'phi':'f','psi':'ps','tau':'t','rho':'p','nu':'v','xi':'E',
                       'Gamma':'G','Delta':'D','Theta':'O','Lambda':'L','Pi':'P',
                       'Sigma':'E','Omega':'Q','Phi':'F','Psi':'PS'}
        for name, sym in _greek_safe.items():
            display = display.replace(f'\\{name}', sym)
        # Math functions
        display = _re.sub(r'\\(sin|cos|tan|sec|csc|cot|log|ln|exp|lim|max|min|det|dim|sup|inf|arg|deg|gcd)\b', r'\1', display)
        # Operators (ASCII safe)
        display = display.replace('\\cdot', '*').replace('\\times', 'x').replace('\\pm', '+/-')
        display = display.replace('\\infty', 'inf').replace('\\neq', '!=').replace('\\leq', '<=')
        display = display.replace('\\geq', '>=').replace('\\approx', '~=')
        display = display.replace('\\rightarrow', '->').replace('\\leftarrow', '<-')
        display = display.replace('\\Rightarrow', '=>').replace('\\partial', 'd')
        display = display.replace('\\nabla', 'V').replace('\\in', 'in')
        # Spacing
        display = display.replace('\\left', '').replace('\\right', '')
        display = display.replace('\\,', ' ').replace('\\;', ' ').replace('\\!', '').replace('\\quad', '  ')
        display = display.replace('\\Big', '').replace('\\big', '').replace('\\bigg', '')
        # Text mode commands
        display = _re.sub(r'\\text\{([^}]*)\}', r'\1', display)
        display = _re.sub(r'\\mathrm\{([^}]*)\}', r'\1', display)
        display = _re.sub(r'\\mathbf\{([^}]*)\}', r'\1', display)
        display = _re.sub(r'\\mathit\{([^}]*)\}', r'\1', display)
        display = _re.sub(r'\\mathbb\{([^}]*)\}', r'\1', display)
        display = _re.sub(r'\\overline\{([^}]*)\}', r'\1', display)
        display = _re.sub(r'\\hat\{([^}]*)\}', r'\1', display)
        display = _re.sub(r'\\vec\{([^}]*)\}', r'\1', display)
        # Remaining commands
        display = _re.sub(r'\\[a-zA-Z]+\{([^}]*)\}', r'\1', display)
        display = _re.sub(r'\\[a-zA-Z]+', '', display)
        display = _re.sub(r'[\$\{\}\\]', '', display).strip() or "?"
        display = _re.sub(r'\s+', ' ', display)

        # Render to temp Cairo SVG, then rewrite with proper <g id='unique000'> groups
        fs = 10
        try:
            import cairo as _cairo
            import tempfile as _tf

            # Measure text
            tmp = _cairo.ImageSurface(_cairo.FORMAT_ARGB32, 1, 1)
            ctx_tmp = _cairo.Context(tmp)
            ctx_tmp.select_font_face("serif", _cairo.FONT_SLANT_NORMAL, _cairo.FONT_WEIGHT_NORMAL)
            ctx_tmp.set_font_size(fs)
            te = ctx_tmp.text_extents(display)
            fe = ctx_tmp.font_extents()
            tmp.finish()

            pad = 1
            w = max(te.x_advance + pad * 2, 4)
            h = max(fe[2] + pad * 2, 4)

            # Render to temp file
            _tmp_path = _tf.mktemp(suffix='.svg')
            surface = _cairo.SVGSurface(_tmp_path, w, h)
            ctx = _cairo.Context(surface)
            ctx.select_font_face("serif", _cairo.FONT_SLANT_NORMAL, _cairo.FONT_WEIGHT_NORMAL)
            ctx.set_font_size(fs)
            ctx.set_source_rgb(1, 1, 1)
            ctx.move_to(pad, fe[0] + pad)
            ctx.text_path(display)
            ctx.fill()
            surface.finish()

            # Read Cairo SVG and inject <g id='unique000'> wrapper
            with open(_tmp_path, 'r') as _f:
                cairo_svg = _f.read()
            _os.unlink(_tmp_path)

            # Extract inner content (everything between <svg...> and </svg>)
            inner_match = _re.search(r'<svg[^>]*>(.*)</svg>', cairo_svg, _re.DOTALL)
            inner = inner_match.group(1).strip() if inner_match else ''

            # Build final SVG with manim-expected <g id='unique000'> structure
            final_svg = (
                f'<?xml version="1.0" encoding="UTF-8"?>\n'
                f'<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" '
                f'width="{w:.4f}" height="{h:.4f}" viewBox="0 0 {w:.4f} {h:.4f}">\n'
                f'<g id="unique000">\n'
                f'{inner}\n'
                f'</g>\n'
                f'</svg>'
            )
            svg_file.write_text(final_svg, encoding='utf-8')
        except Exception:
            display_esc = display.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
            w = max(len(display) * fs * 0.6, 20)
            h = fs * 1.5
            svg_content = (f'<svg xmlns="http://www.w3.org/2000/svg" width="{w}" height="{h}">'
                          f'<text x="0" y="{fs}" font-size="{fs}" fill="white">{display_esc}</text></svg>')
            svg_file.write_text(svg_content, encoding="utf-8")
        return svg_file

    dvi_file = compile_tex(
        tex_file,
        tex_template.tex_compiler,
        tex_template.output_format,
    )
    svg_file = convert_to_svg(dvi_file, tex_template.output_format)
    if not config["no_latex_cleanup"]:
        delete_nonsvg_files()
    return svg_file


def generate_tex_file(
    expression: str,
    environment: str | None = None,
    tex_template: TexTemplate | None = None,
) -> Path:
    r"""Takes a tex expression (and an optional tex environment),
    and returns a fully formed tex file ready for compilation.

    Parameters
    ----------
    expression
        String containing the TeX expression to be rendered, e.g. ``\\sqrt{2}`` or ``foo``
    environment
        The string containing the environment in which the expression should be typeset, e.g. ``align*``
    tex_template
        Template class used to typesetting. If not set, use default template set via `config["tex_template"]`

    Returns
    -------
    :class:`Path`
        Path to generated TeX file
    """
    if tex_template is None:
        tex_template = config["tex_template"]
    if environment is not None:
        output = tex_template.get_texcode_for_expression_in_env(expression, environment)
    else:
        output = tex_template.get_texcode_for_expression(expression)

    tex_dir = config.get_dir("tex_dir")
    tex_dir.mkdir(parents=True, exist_ok=True)

    result = tex_dir / (tex_hash(output) + ".tex")
    if not result.exists():
        logger.info(
            "Writing %(expression)s to %(path)s",
            {"expression": expression, "path": f"{result}"},
        )
        result.write_text(output, encoding="utf-8")
    return result


def make_tex_compilation_command(
    tex_compiler: str, output_format: str, tex_file: Path, tex_dir: Path
) -> list[str]:
    """Prepares the TeX compilation command, i.e. the TeX compiler name
    and all necessary CLI flags.

    Parameters
    ----------
    tex_compiler
        String containing the compiler to be used, e.g. ``pdflatex`` or ``lualatex``
    output_format
        String containing the output format generated by the compiler, e.g. ``.dvi`` or ``.pdf``
    tex_file
        File name of TeX file to be typeset.
    tex_dir
        Path to the directory where compiler output will be stored.

    Returns
    -------
    :class:`list[str]`
        Compilation command according to given parameters
    """
    if tex_compiler in {"latex", "pdflatex", "luatex", "lualatex"}:
        command = [
            tex_compiler,
            "-interaction=batchmode",
            f"-output-format={output_format[1:]}",
            "-halt-on-error",
            f"-output-directory={tex_dir.as_posix()}",
            f"{tex_file.as_posix()}",
        ]
    elif tex_compiler == "xelatex":
        if output_format == ".xdv":
            outflag = ["-no-pdf"]
        elif output_format == ".pdf":
            outflag = []
        else:
            raise ValueError("xelatex output is either pdf or xdv")
        command = [
            "xelatex",
            *outflag,
            "-interaction=batchmode",
            "-halt-on-error",
            f"-output-directory={tex_dir.as_posix()}",
            f"{tex_file.as_posix()}",
        ]
    else:
        raise ValueError(f"Tex compiler {tex_compiler} unknown.")
    return command


def insight_inputenc_error(matching: Match[str]) -> Generator[str]:
    code_point = chr(int(matching[1], 16))
    name = unicodedata.name(code_point)
    yield f"TexTemplate does not support character '{name}' (U+{matching[1]})."
    yield "See the documentation for manim.mobject.svg.tex_mobject for details on using a custom TexTemplate."


def insight_package_not_found_error(matching: Match[str]) -> Generator[str]:
    yield f"You do not have package {matching[1]} installed."
    yield f"Install {matching[1]} it using your LaTeX package manager, or check for typos."


def compile_tex(tex_file: Path, tex_compiler: str, output_format: str) -> Path:
    """Compiles a tex_file into a .dvi or a .xdv or a .pdf

    Parameters
    ----------
    tex_file
        File name of TeX file to be typeset.
    tex_compiler
        String containing the compiler to be used, e.g. ``pdflatex`` or ``lualatex``
    output_format
        String containing the output format generated by the compiler, e.g. ``.dvi`` or ``.pdf``

    Returns
    -------
    :class:`Path`
        Path to generated output file in desired format (DVI, XDV or PDF).
    """
    result = tex_file.with_suffix(output_format)
    tex_dir = config.get_dir("tex_dir")
    if not result.exists():
        # iOS: no LaTeX compiler available
        import sys
        if hasattr(sys, 'getandroidapilevel') or 'iPhoneOS' in str(getattr(sys, 'platform', '')) or 'iOS' in str(getattr(sys, '_stdlib_dir', '')):
            raise ValueError(
                "LaTeX compilation is not available on iOS. "
                "Use Text() instead of Tex()/MathTex() for text rendering, "
                "or use MathJax-compatible alternatives."
            )
        command = make_tex_compilation_command(
            tex_compiler,
            output_format,
            tex_file,
            tex_dir,
        )
        cp = subprocess.run(command, stdout=subprocess.DEVNULL)
        if cp.returncode != 0:
            log_file = tex_file.with_suffix(".log")
            print_all_tex_errors(log_file, tex_compiler, tex_file)
            raise ValueError(
                f"{tex_compiler} error converting to"
                f" {output_format[1:]}. See log output above or"
                f" the log file: {log_file}",
            )
    return result


def convert_to_svg(dvi_file: Path, extension: str, page: int = 1) -> Path:
    """Converts a .dvi, .xdv, or .pdf file into an svg using dvisvgm.

    Parameters
    ----------
    dvi_file
        File name of the input file to be converted.
    extension
        String containing the file extension and thus indicating the file type, e.g. ``.dvi`` or ``.pdf``
    page
        Page to be converted if input file is multi-page.

    Returns
    -------
    :class:`Path`
        Path to generated SVG file.
    """
    result = dvi_file.with_suffix(".svg")
    if not result.exists():
        command = [
            "dvisvgm",
            *(["--pdf"] if extension == ".pdf" else []),
            f"--page={page}",
            "--no-fonts",
            "--verbosity=0",
            f"--output={result.as_posix()}",
            f"{dvi_file.as_posix()}",
        ]
        subprocess.run(command, stdout=subprocess.DEVNULL)

    # if the file does not exist now, this means conversion failed
    if not result.exists():
        raise ValueError(
            f"Your installation does not support converting {dvi_file.suffix} files to SVG."
            f" Consider updating dvisvgm to at least version 2.4."
            f" If this does not solve the problem, please refer to our troubleshooting guide at:"
            f" https://docs.manim.community/en/stable/faq/general.html#my-installation-"
            f"does-not-support-converting-pdf-to-svg-help",
        )

    return result


def delete_nonsvg_files(additional_endings: Iterable[str] = ()) -> None:
    """Deletes every file that does not have a suffix in ``(".svg", ".tex", *additional_endings)``

    Parameters
    ----------
    additional_endings
        Additional endings to whitelist
    """
    tex_dir = config.get_dir("tex_dir")
    file_suffix_whitelist = {".svg", ".tex", *additional_endings}

    for f in tex_dir.iterdir():
        if f.suffix not in file_suffix_whitelist:
            f.unlink()


def print_all_tex_errors(log_file: Path, tex_compiler: str, tex_file: Path) -> None:
    if not log_file.exists():
        raise RuntimeError(
            f"{tex_compiler} failed but did not produce a log file. "
            "Check your LaTeX installation.",
        )
    with log_file.open(encoding="utf-8") as f:
        tex_compilation_log = f.readlines()
    error_indices = [
        index for index, line in enumerate(tex_compilation_log) if line.startswith("!")
    ]
    if error_indices:
        with tex_file.open(encoding="utf-8") as f:
            tex = f.readlines()
        for error_index in error_indices:
            print_tex_error(tex_compilation_log, error_index, tex)


LATEX_ERROR_INSIGHTS = [
    (
        r"inputenc Error: Unicode character (?:.*) \(U\+([0-9a-fA-F]+)\)",
        insight_inputenc_error,
    ),
    (
        r"LaTeX Error: File `(.*?[clsty])' not found",
        insight_package_not_found_error,
    ),
]


def print_tex_error(
    tex_compilation_log: Sequence[str],
    error_start_index: int,
    tex_source: Sequence[str],
) -> None:
    logger.error(
        f"LaTeX compilation error: {tex_compilation_log[error_start_index][2:]}",
    )

    # TeX errors eventually contain a line beginning 'l.xxx` where xxx is the line number that caused the compilation
    # failure. This code finds the next such line after the error current error message
    line_of_tex_error = (
        int(
            [
                log_line
                for log_line in tex_compilation_log[error_start_index:]
                if log_line.startswith("l.")
            ][0]
            .split(" ")[0]
            .split(".")[1],
        )
        - 1
    )
    # our tex error may be on a line outside our user input because of post-processing
    if line_of_tex_error >= len(tex_source):
        return None

    context = ["Context of error: \n"]
    if line_of_tex_error < 3:
        context += tex_source[: line_of_tex_error + 3]
        context[-4] = "-> " + context[-4]
    elif line_of_tex_error > len(tex_source) - 3:
        context += tex_source[line_of_tex_error - 1 :]
        context[1] = "-> " + context[1]
    else:
        context += tex_source[line_of_tex_error - 3 : line_of_tex_error + 3]
        context[-4] = "-> " + context[-4]

    context_joined = "".join(context)
    logger.error(context_joined)

    for insights in LATEX_ERROR_INSIGHTS:
        prob, get_insight = insights
        matching = re.search(
            prob,
            "".join(tex_compilation_log[error_start_index])[2:],
        )
        if matching is not None:
            for insight in get_insight(matching):
                logger.info(insight)
